package com.github.namuan.fintech.controls;
import java.time.Instant; import java.util.HashSet; import java.util.Set;
public final class MakerCheckerRequest { private final String id; private final String requesterId; private final String action; private final Instant requestedAt; private final Set<String> approvers = new HashSet<>(); public MakerCheckerRequest(String id,String requesterId,String action,Instant requestedAt){this.id=id;this.requesterId=requesterId;this.action=action;this.requestedAt=requestedAt;} public void approve(String approverId, ApprovalPolicy policy){ if(!policy.requesterMayApprove() && requesterId.equals(approverId)) throw new IllegalArgumentException("requester cannot approve"); approvers.add(approverId);} public boolean approved(ApprovalPolicy policy){ return approvers.size() >= policy.requiredApprovers(); } public String id(){return id;} public String requesterId(){return requesterId;} public String action(){return action;} public Instant requestedAt(){return requestedAt;} public Set<String> approvers(){return Set.copyOf(approvers);} }
